int main() {
    int a = 0xAB;   // 171 = 10101011
    int b = 0x0F;   // 15  = 00001111
    // AND: 10101011 & 00001111 = 00001011 = 11
    int c = a & b;
    // OR:  10101011 | 00001111 = 10101111 = 175
    int d = a | b;
    // XOR: 10101011 ^ 00001111 = 10100100 = 164
    int e = a ^ b;
    // Combine: c + d + e = 11 + 175 + 164 = 350
    return c + d + e;
}
